using System.Collections;

class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: on Linux, GetEnvironmentVariable returns null
        // for empty-string vars. Use GetEnvironmentVariables() to distinguish
        // "not set" from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        IDictionary allVars = Environment.GetEnvironmentVariables();
        if (!allVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

